<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Spreadsheet</title>
<style>
  body { font-family: sans-serif; margin: 20px; }
  #app { display: grid; grid-template-columns: 40px repeat(10, 1fr); gap: 1px; border: 1px solid #ccc; background: #eee; width: 650px; height: 450px; margin-bottom: 20px; }
  .header-col { background: #f9f9f9; font-weight: bold; display: flex; align-items: center; justify-content: center; border-right: 1px solid #ccc; }
  .header-row { background: #f9f9f9; font-weight: bold; display: flex; align-items: center; justify-content: center; border-bottom: 1px solid #ccc; }
  input.cell { width: 100%; height: 100%; border: none; outline: none; padding: 4px; box-sizing: border-box; font-size: 12px; text-align: right; background: white; color: black; }
  input.cell:focus { background: #eef; border: 1px solid blue; }
  button { margin-top: 10px; padding: 5px 10px; cursor: pointer; font-size: 14px; }
</style>
</head>
<body>

<div id="app"></div>
<button id="export">Export CSV</button>
<textarea id="csv" rows="5" cols="80"></textarea>

<script>
(function() {
    const COLS = 10;
    const ROWS = 10;

    // State
    const cells = {}; // "A1" -> { raw: "", display: "" }
    const dependents = {}; // "A1" -> ["B2", ...] (Who depends on A1)
    const dependencies = {}; // "A1" -> ["B2", ...] (What A1 depends on)

    const appDiv = document.getElementById('app');
    const exportBtn = document.getElementById('export');
    const csvArea = document.getElementById('csv');

    // Helper to get cell ID from row/col index
    function getCellId(col, row) {
        return String.fromCharCode(65 + col - 1) + row;
    }

    // Initialize Grid
    function initGrid() {
        for (let r = 1; r <= ROWS; r++) {
            // Header Row
            const headerRow = document.createElement('div');
            headerRow.className = 'header-row';
            headerRow.id = `row-${r}`;

            for (let c = 0; c < COLS; c++) {
                const cellId = getCellId(c + 1, r);
                const input = document.createElement('input');
                input.className = 'cell';
                input.id = `cell-${cellId}`;
                input.type = 'text';

                // Add to DOM
                headerRow.appendChild(input);

                // Init State
                cells[cellId] = { raw: "", display: "" };

                // Add listeners
                input.addEventListener('input', (e) => handleInput(e, cellId));
                input.addEventListener('blur', (e) => handleBlur(e, cellId));
                input.addEventListener('keydown', (e) => handleKeydown(e, cellId));
            }

            // Row Header
            const rowHeader = document.createElement('div');
            rowHeader.className = 'header-col';
            rowHeader.textContent = r;
            appDiv.appendChild(rowHeader);
            appDiv.appendChild(headerRow);
        }
    }

    function handleInput(e, id) {
        const input = e.target;
        cells[id].raw = input.value;

        // If it's a formula, try to update immediately (live preview)
        if (input.value.startsWith('=')) {
            recalculate(id);
        } else {
            // Plain text: display as is
            cells[id].display = input.value || "";
            input.value = cells[id].display;
        }
    }

    function handleBlur(e, id) {
        const input = e.target;
        // Commit the value to raw state
        cells[id].raw = input.value;

        // Recalculate everything affected
        recalculate(id);
    }

    function handleKeydown(e, id) {
        if (e.key === 'Enter') {
            const input = e.target;
            cells[id].raw = input.value;
            recalculate(id);
        }
    }

    // Update dependency maps based on raw text
    function updateDependenciesMap(id) {
        const raw = cells[id].raw;

        // Clear existing dependencies for this cell
        dependencies[id] = [];

        if (!raw || !raw.startsWith('=')) {
            dependents[id] = []; // Plain text has no dependencies
            return;
        }

        // Extract references from formula
        const refRegex = /[A-J][1-9]?[0-9]?/g;
        const refs = raw.match(refRegex) || [];

        dependencies[id] = refs;

        // Update reverse map (dependents)
        for (let ref of refs) {
            if (!dependents[ref]) dependents[ref] = [];
            dependents[ref].push(id);
        }
    }

    function recalculate(startId) {
        updateDependenciesMap(startId);

        // Check for cycles involving startId
        const cycleNodes = findCycle(startId);

        if (cycleNodes.length > 0) {
            // Mark all nodes in the cycle as #CYCLE
            for (let node of cycleNodes) {
                cells[node].display = "#CYCLE";
            }
            return;
        }

        // If no cycle, calculate value for startId
        const result = evaluateFormula(startId);

        if (result === '#CYCLE') {
            cells[startId].display = "#CYCLE";
        } else {
            cells[startId].display = result;
        }

        // Propagate to dependents
        const dependentList = dependents[startId] || [];
        for (let dep of dependentList) {
            recalculate(dep);
        }
    }

    // DFS to find cycles in the dependency graph
    function findCycle(startId) {
        const visited = new Set();
        const stack = [startId];
        const path = [];

        while (stack.length > 0) {
            const node = stack.pop();

            if (visited.has(node)) continue;
            visited.add(node);

            // Add to current path for cycle detection logic? 
            // Actually, we need to detect back-edges.
            // Let's use a standard DFS with recursion stack tracking.
        }

        // Re-implementing with explicit recursion stack tracking
        const visiting = new Set();
        const visitedSet = new Set();

        function dfs(node) {
            if (visiting.has(node)) {
                // Cycle detected! Return all nodes in the current path from node to start?
                // Actually, we just need to mark everyone involved.
                // Since we are traversing dependencies, if we hit a node currently being visited, it's a cycle.
                return true; 
            }

            if (visitedSet.has(node)) return false;

            visiting.add(node);

            const deps = dependencies[node] || [];
            for (let dep of deps) {
                if (dfs(dep)) {
                    // Cycle found involving this branch.
                    // We need to mark all nodes in the 'visiting' set as part of a cycle?
                    // Not necessarily all, but usually spreadsheets mark the whole loop.
                    // For simplicity, we'll return true up the stack and mark everything in visiting.
                }
            }

            visiting.delete(node);
            visitedSet.add(node);
            return false;
        }

        if (dfs(startId)) {
            // If cycle found, mark all nodes currently in 'visiting' as #CYCLE?
            // Actually, the standard way is to mark all nodes that are part of the cycle.
            // But since we don't have the exact path easily without more complex logic,
            // and given the constraints, marking all nodes reachable from startId that lead back to startId is hard.
            // However, a simpler heuristic for this specific prompt:
            // If A1 depends on B2 and B2 depends on A1.
            // When updating A1, we traverse A1 -> B2 -> A1.
            // We can just mark all nodes in the 'visiting' set when we detect a back-edge.

            // Let's refine:
            // If dfs returns true, it means we found a cycle.
            // We need to identify which nodes are part of it.
            // A simple way is to check if any node in dependencies leads back to startId or itself.
        }

        return [];
    }

    // Refined Cycle Detection Logic
    function findCycle(startId) {
        const visited = new Set();
        const recStack = new Set();

        function dfs(node, path) {
            if (recStack.has(node)) {
                // Found a cycle. Mark all nodes in the current recursion stack that are part of this loop.
                // Since we don't track the exact loop easily without more state, 
                // and given the prompt "display exactly #CYCLE in every cell of the cycle",
                // we can mark all nodes currently in 'recStack' as they form a component of the cycle?
                // Actually, if A1->B2->A1. Path: [A1, B2]. Next is A1. Cycle detected.
                // Nodes in cycle: A1, B2.
                // We can just return true and mark all nodes in 'recStack' as #CYCLE?
                // Wait, if A1->B2->C3->D4->A1. Path [A1, B2, C3, D4]. Next A1.
                // All 4 are in cycle.
                // So yes, mark all nodes in recStack.

                for (let n of recStack) {
                    cells[n].display = "#CYCLE";
                }
                return true;
            }

            if (visited.has(node)) return false;

            visited.add(node);
            recStack.add(node);

            const deps = dependencies[node] || [];
            for (let dep of deps) {
                if (dfs(dep, path)) return true;
            }

            recStack.delete(node);
            return false;
        }

        // We need to check if startId is part of a cycle.
        // But wait, if A1->B2 and B2->A1. StartId=A1.
        // dfs(A1) -> visits A1 (recStack={A1}) -> calls dfs(B2).
        // dfs(B2) -> visits B2 (recStack={A1, B2}) -> calls dfs(A1).
        // dfs(A1) sees A1 in recStack. Returns true.
        // We mark all in recStack ({A1, B2}). Correct.

        // What if A1->B2 and B2->C3 (no cycle). StartId=A1.
        // dfs(A1) -> visits A1 -> calls dfs(B2).
        // dfs(B2) -> visits B2 -> calls dfs(C3).
        // dfs(C3) -> no deps. Returns false.
        // Back to B2. Returns false.
        // Back to A1. Returns false.
        // Correct.

        dfs(startId, []);

        // Check if any cell was marked? 
        // The function above marks cells directly. But we need to know IF a cycle exists for the caller.
        // Let's refactor slightly to separate detection and marking.

        const cycleNodes = [];
        const visitedGlobal = new Set();
        const recStackGlobal = new Set();

        function checkCycle(node) {
            if (recStackGlobal.has(node)) {
                // Cycle detected. Mark all in stack.
                for (let n of recStackGlobal) {
                    cells[n].display = "#CYCLE";
                    cycleNodes.push(n);
                }
                return true;
            }

            if (visitedGlobal.has(node)) return false;

            visitedGlobal.add(node);
            recStackGlobal.add(node);

            const deps = dependencies[node] || [];
            for (let dep of deps) {
                if (checkCycle(dep)) return true;
            }

            recStackGlobal.delete(node);
            return false;
        }

        checkCycle(startId);

        // If no cycle was found, we still need to calculate the value.
        // But wait, if A1->B2->A1, and we start at A1.
        // checkCycle(A1) marks A1 and B2 as #CYCLE.
        // Then we return from recalculate.
        // This is correct.

        return cycleNodes;
    }

    function evaluateFormula(id) {
        const raw = cells[id].raw;
        if (!raw || !raw.startsWith('=')) {
            return raw || "";
        }

        let expr = raw.substring(1).trim();

        try {
            const tokens = tokenize(expr);
            if (!tokens) return "#ERR"; 

            // Resolve references to values
            const context = {};
            for (let i = 0; i < COLS; i++) {
                for (let j = 1; j <= ROWS; j++) {
                    const cid = getCellId(i + 1, j);
                    const val = cells[cid].display; // Use display value (computed)

                    if (val === '#CYCLE' || val === '#ERR') {
                        context[cid] = "#ERR"; 
                    } else {
                        const num = parseFloat(val);
                        context[cid] = isNaN(num) ? val : num;
                    }
                }
            }

            // Parse and Evaluate
            const parser = new Parser(tokens, context);
            const result = parser.parse();

            if (result === '#CYCLE') return '#CYCLE';
            if (result === '#ERR') return '#ERR';

            return String(result);
        } catch (e) {
            return "#ERR";
        }
    }

    function tokenize(expr) {
        const tokens = [];
        let i = 0;
        while (i < expr.length) {
            const char = expr[i];

            // Number
            if (/[0-9.]/.test(char)) {
                let numStr = "";
                while (i < expr.length && /[0-9.]/.test(expr[i])) {
                    numStr += expr[i];
                    i++;
                }
                tokens.push({ type: 'NUM', value: parseFloat(numStr) });
            }
            // Cell Ref
            else if (/^[A-J]$/.test(char)) {
                let ref = char;
                i++;
                while (i < expr.length && /[0-9]/.test(expr[i])) { 
                    ref += expr[i];
                    i++;
                }
                tokens.push({ type: 'REF', value: ref });
            }
            // Operators and Parentheses
            else if (['+', '-', '*', '/', '(', ')'].includes(char)) {
                tokens.push({ type: char, value: char });
                i++;
            }
            else {
                return null; // Syntax Error
            }
        }
        return tokens;
    }

    class Parser {
        constructor(tokens, context) {
            this.tokens = tokens;
            this.pos = 0;
            this.context = context;
        }

        parse() {
            let result = this.expr();
            if (this.pos < this.tokens.length) {
                return "#ERR"; 
            }
            return result;
        }

        expr() {
            let left = this.term();
            while (this.peek() === '+') {
                this.consume('+');
                const right = this.term();
                left += right;
            }
            while (this.peek() === '-') {
                this.consume('-');
                const right = this.term();
                left -= right;
            }
            return left;
        }

        term() {
            let left = this.factor();
            while (this.peek() === '*') {
                this.consume('*');
                const right = this.factor();
                left *= right;
            }
            while (this.peek() === '/') {
                this.consume('/');
                const right = this.factor();
                if (right === 0) return "#ERR"; 
                left /= right;
            }
            return left;
        }

        factor() {
            const token = this.peek();

            if (token === '(') {
                this.consume('(');
                let result = this.expr();
                this.consume(')');
                return result;
            } else if (token.type === 'NUM') {
                return this.consume().value;
            } else if (token.type === 'REF') {
                const refId = token.value;
                if (this.context[refId] === '#CYCLE') {
                    return '#CYCLE';
                }
                if (this.context[refId] === '#ERR') {
                    return '#ERR';
                }
                return this.context[refId];
            } else {
                return "#ERR";
            }
        }

        peek() {
            return this.tokens[this.pos];
        }

        consume(expected) {
            const token = this.peek();
            if (token && token.value === expected) {
                this.pos++;
                return token;
            } else {
                throw new Error("Syntax Error");
            }
        }
    }

    // API Implementation
    window.sheet = {
        set: function(id, text) {
            const input = document.getElementById(`cell-${id}`);
            if (input) {
                cells[id].raw = text;
                input.value = text;
                recalculate(id);
            }
        },
        get: function(id) {
            return cells[id] ? cells[id].display : "";
        },
        raw: function(id) {
            return cells[id] ? cells[id].raw : "";
        }
    };

    // Export Logic
    exportBtn.addEventListener('click', () => {
        let csvContent = "";
        for (let r = 1; r <= ROWS; r++) {
            let rowStr = "";
            for (let c = 0; c < COLS; c++) {
                const id = getCellId(c + 1, r);
                const val = window.sheet.get(id);
                rowStr += (c > 0 ? "," : "") + val;
            }
            csvContent += rowStr + "\n";
        }
        csvArea.value = csvContent;
    });

    initGrid();

})();
</script>
</body>
</html>
